// Single Shiki theme for the docs, shared by satteri/hast-plugins.mjs (fenced
// MDX blocks) and loaders/demo-loader.mjs (demo source tabs). Instead of
// shiki's dual-theme output (inline --shiki-light/--shiki-dark color values on
// every token), the two github themes are zipped rule-by-rule into ONE theme
// whose every color is a `var(--shiki-*)` reference; the classTokens
// transformer then turns each span's inline style into `sk-*` classes. Both
// the classes and the var values live in src/components/shiki-theme.css
// (generated by scripts/build-shiki-theme.mjs, gitignored), resolved per theme
// via light-dark(). Both are Primer themes generated from the same source, so
// their tokenColors are structurally parallel — build() throws if an update
// ever breaks that.
// Light is github-light-default: material-theme-lighter's oranges/teals fall
// well below WCAG AA contrast on surface-container.
export const SHIKI_THEMES = { light: "github-light-default", dark: "github-dark-dimmed" };

// var(--shiki-keyword) as color → sk-keyword; as background → sk-bg-keyword.
const COLOR_DECL_RE = /^(color|background-color):var\(--shiki-([\w-]+)\)$/;
// fontStyle declarations shiki can emit, mapped to utility classes.
const STYLE_CLASSES = {
  "font-style:italic": "sk-italic",
  "font-weight:bold": "sk-bold",
  "text-decoration:underline": "sk-underline",
  "text-decoration:line-through": "sk-strikethrough",
};

// Rewrites shiki's inline styles to shiki-theme.css classes: token spans get
// sk-* classes; the pre's own color/background come from docs CSS (mdx pre /
// DemoCodeTabs classes), so its style is dropped entirely. An unrecognized
// declaration stays inline rather than being lost.
export const classTokens = {
  pre(node) {
    delete node.properties.style;
  },
  span(node) {
    const style = node.properties?.style;
    if (typeof style !== "string") return;
    const classes = [];
    const rest = [];
    for (const decl of style.split(";").filter(Boolean)) {
      const m = COLOR_DECL_RE.exec(decl);
      if (m) classes.push(m[1] === "color" ? `sk-${m[2]}` : `sk-bg-${m[2]}`);
      else if (STYLE_CLASSES[decl]) classes.push(STYLE_CLASSES[decl]);
      else rest.push(decl);
    }
    if (!classes.length) return;
    node.properties.class = [node.properties.class, ...classes].filter(Boolean).join(" ");
    if (rest.length) node.properties.style = rest.join(";");
    else delete node.properties.style;
  },
};

let buildPromise;
export function getShikiTheme() {
  return (buildPromise ??= build()).then((b) => b.theme);
}
export function getShikiThemeCss() {
  return (buildPromise ??= build()).then((b) => b.css);
}

// "entity.name.tag, support.class.component" → "entity-name-tag"
function hintFrom(scope) {
  const first = String(Array.isArray(scope) ? scope[0] : scope);
  return first.replace(/[^a-zA-Z0-9]+/g, "-").toLowerCase();
}

const pairKey = (l, d) => `${l}|${d}`.toLowerCase();

const skClass = (varName) => varName.replace(/^--shiki-/, "sk-");

async function build() {
  // Dynamic import keeps shiki lazy for consumers that never highlight.
  const { bundledThemes } = await import("shiki");
  const light = (await bundledThemes[SHIKI_THEMES.light]()).default;
  const dark = (await bundledThemes[SHIKI_THEMES.dark]()).default;
  if (light.tokenColors.length !== dark.tokenColors.length)
    throw new Error("shiki themes no longer zip: tokenColors length mismatch");

  // A color pair is shared by many rules; name its var after the best-known
  // scope among them (PREFERRED order), falling back to the shortest one —
  // "keyword" beats "constant.other.placeholder".
  const PREFERRED = [
    "keyword",
    "string",
    "comment",
    "constant",
    "variable",
    "entity.name.function",
    "entity.name.tag",
    "support",
    "punctuation",
  ];
  const scopesByPair = new Map(); // key → Set of first scopes
  for (let i = 0; i < light.tokenColors.length; i++) {
    for (const prop of ["foreground", "background"]) {
      const l = light.tokenColors[i].settings?.[prop];
      if (!l) continue;
      const key = pairKey(l, dark.tokenColors[i].settings?.[prop]);
      const scope = light.tokenColors[i].scope;
      (scopesByPair.get(key) ?? scopesByPair.set(key, new Set()).get(key)).add(
        String(Array.isArray(scope) ? scope[0] : scope),
      );
    }
  }
  const hintByPair = new Map();
  hintByPair.set(
    pairKey(light.colors["editor.foreground"], dark.colors["editor.foreground"]),
    "fg",
  );
  for (const [key, scopes] of scopesByPair) {
    if (hintByPair.has(key)) continue;
    const best =
      PREFERRED.find((p) => scopes.has(p)) ??
      [...scopes].toSorted((a, b) => a.length - b.length || a.localeCompare(b))[0];
    hintByPair.set(key, hintFrom(best));
  }

  const varByPair = new Map(); // "#light|#dark" → --shiki-* name
  const used = new Set();
  const fgVars = new Set(); // vars referenced as color / background — each
  const bgVars = new Set(); // needs a class rule in the generated css
  const varFor = (lightColor, darkColor, hint) => {
    const key = pairKey(lightColor, darkColor);
    let name = varByPair.get(key);
    if (!name) {
      const base = `--shiki-${hintByPair.get(key) ?? hint}`;
      name = base;
      for (let n = 2; used.has(name); n++) name = `${base}-${n}`;
      used.add(name);
      varByPair.set(key, name);
    }
    return name;
  };

  const fgVar = varFor(light.colors["editor.foreground"], dark.colors["editor.foreground"], "fg");
  fgVars.add(fgVar);
  const tokenColors = light.tokenColors.map((ruleL, i) => {
    const ruleD = dark.tokenColors[i];
    if (JSON.stringify(ruleL.scope) !== JSON.stringify(ruleD.scope))
      throw new Error(`shiki themes no longer zip: scope mismatch at rule ${i}`);
    const settings = { ...ruleL.settings };
    for (const prop of ["foreground", "background"]) {
      if (!settings[prop]) continue;
      const name = varFor(ruleL.settings[prop], ruleD.settings[prop], hintFrom(ruleL.scope));
      (prop === "foreground" ? fgVars : bgVars).add(name);
      settings[prop] = `var(${name})`;
    }
    return { ...ruleL, settings };
  });

  const theme = {
    name: "md3-docs",
    type: "light",
    colors: {
      "editor.foreground": `var(${fgVar})`,
      // Never rendered (classTokens drops the pre style) but required valid.
      "editor.background": light.colors["editor.background"],
    },
    tokenColors,
  };

  const decls = [...varByPair].map(([pair, name]) => {
    const [l, d] = pair.split("|");
    return `    ${name}: ${l === d ? l : `light-dark(${l}, ${d})`};`;
  });
  const classRules = [
    ...[...fgVars].map((v) => `  .${skClass(v)} { color: var(${v}); }`),
    ...[...bgVars].map(
      (v) => `  .${skClass(v).replace(/^sk-/, "sk-bg-")} { background-color: var(${v}); }`,
    ),
    ...Object.entries(STYLE_CLASSES).map(
      ([decl, cls]) => `  .${cls} { ${decl.replace(":", ": ")}; }`,
    ),
  ];
  const css = `/* Generated by scripts/build-shiki-theme.mjs from ${SHIKI_THEMES.light} +
   ${SHIKI_THEMES.dark} — do not edit. light-dark() resolves against the nearest
   color-scheme, set by the [data-theme] blocks in tokens.css. */
@layer components {
  .shiki {
${decls.join("\n")}
  }

${classRules.join("\n")}
}
`;
  return { theme, css };
}
